// 1. Pega todos os itens que chegaram no nó
const items = $input.all();

// Prevenção de erro: se a lista estiver vazia, encerra elegantemente
if (items.length === 0) {
  return [{ json: { manual_completo: "Nenhuma regra encontrada." } }];
}

// 2. Extrai o nome do jogo (usamos o primeiro item da lista como referência)
const nomeJogo = items[0].json.nome_jogo;

// 3. Monta o Sumário iterando sobre os títulos
let sumario = `## Sumário\n\n`;
for (const item of items) {
  sumario += `* ${item.json.titulo_regra}\n`;
}

// 4. Monta o Corpo do Manual com as descrições
let corpoRegras = `## Regras do Jogo\n\n`;
for (const item of items) {
  // Adiciona o título da regra como cabeçalho (##)
  corpoRegras += `## ${item.json.titulo_regra}\n\n`;

  // Adiciona o conteúdo detalhado gerado pela IA
  corpoRegras += `${item.json.conteudo_regra}\n\n`;

  // Adiciona uma linha divisória do Markdown (---) para separar visualmente as regras
  corpoRegras += `---\n\n`; 
}

// 5. Junta todas as partes em uma única string de Markdown
const textoFinal = `# Manual de Regras: ${nomeJogo}\n\n${sumario}\n${corpoRegras}`;

// 6. Retorna um ÚNICO item contendo o manual completo consolidado
return [{
  json: {
    nome_jogo: nomeJogo,
    manual_completo: textoFinal
  }
}];

try {
  // 1. Pega a string bruta que a IA gerou (dentro do campo 'output')
  const textoDaIA = $input.first().json.output;

  // 2. Transforma a string de texto em um Array JSON real
  const capitulos = JSON.parse(textoDaIA);

  // 3. Mapeia a lista para o formato nativo do n8n (múltiplos itens)
  // Cada capítulo vai se tornar um "pacote" que o seu nó de Loop vai processar um por vez
  return capitulos.map(capitulo => {
    return {
      json: {
        titulo_capitulo: capitulo.titulo_capitulo,
        query_de_busca: capitulo.query_de_busca
      }
    };
  });

} catch (error) {
  // BLINDAGEM: Se a IA gaguejar e não retornar um JSON perfeito, avisa o erro
  // sem quebrar o fluxo inteiro de forma fatal.
  return [
    {
      json: {
        titulo_capitulo: "ERRO DE PARSE",
        query_de_busca: "A IA não retornou um JSON válido.",
        detalhe_tecnico: error.message
      }
    }
  ];
}

const results = [];

for (const item of items) {
  const titulo = item.json.titulo_regra;
  const conteudo = item.json.conteudo_regra;

  // Monta a string contendo apenas o nome da regra e a descrição
  const textoCombinado = `Regra: ${titulo}\n\n${conteudo}`;

  results.push({
    json: {
      texto_rag: textoCombinado // Apenas este campo será retornado
    }
  });
}

return results;
